INSERT INTO entries (lang, lb_id, difficulty, page, title, tags, summary, content, eg_in, eg_out) VALUES 
('python', 121, 'intermediate', 1, '类的定义与实例化', '["类","实例化"]', '学习如何定义类和创建类的实例。', '在Python中，类使用class关键字定义。\n实例化是通过调用类来创建对象。\n示例代码展示如何定义类和创建实例。', '["class Dog:\\n    def __init__(self, name):\\n        self.name = name\\n\\ndog1 = Dog(\\"Buddy\\")\\nprint(dog1.name)", "class Car:\\n    def __init__(self, brand):\\n        self.brand = brand\\n\\ncar1 = Car(\\"Toyota\\")"]', '["Buddy", ""]'),
('python', 122, 'intermediate', 1, '继承', '["继承","父类","子类"]', '理解类如何从其他类继承属性和方法。', '继承允许子类复用父类的代码。\n使用class Child(Parent):语法。\n子类可以重写父类方法。', '["class Animal:\\n    def speak(self):\\n        return \\"Animal speaks\\"\\n\\nclass Dog(Animal):\\n    pass\\n\\ndog = Dog()\\nprint(dog.speak())"]', '["Animal speaks"]'),
('python', 123, 'intermediate', 1, '多态', '["多态","方法重写"]', '掌握多态概念，允许不同类对象对同一消息做出响应。', '多态使得不同类的对象可以以统一方式操作。\n通过方法重写实现。', '["class Animal:\\n    def speak(self):\\n        return \\"Animal speaks\\"\\n\\nclass Dog(Animal):\\n    def speak(self):\\n        return \\"Woof!\\"\\n\\nanimal = Animal()\\ndog = Dog()\\nprint(animal.speak())\\nprint(dog.speak())"]', '["Animal speaks", "Woof!"]'),
('python', 124, 'intermediate', 1, '封装', '["封装","私有属性"]', '了解封装，隐藏对象内部状态并提供公共接口。', '封装通过命名约定实现私有性，如使用下划线前缀。\n提供getter和setter方法控制访问。', '["class BankAccount:\\n    def __init__(self, balance):\\n        self._balance = balance  # 私有属性\\n    def get_balance(self):\\n        return self._balance\\n\\naccount = BankAccount(100)\\nprint(account.get_balance())"]', '["100"]'),
('python', 125, 'intermediate', 1, '类方法和静态方法', '["类方法","静态方法"]', '区分类方法和静态方法的使用。', '类方法使用@classmethod装饰器，操作类属性。\n静态方法使用@staticmethod装饰器，与类相关但不需要实例或类参数。', '["class MyClass:\\n    class_var = 0\\n    @classmethod\\n    def increment_class_var(cls):\\n        cls.class_var += 1\\n    @staticmethod\\n    def static_method():\\n        return \\"Static method called\\"\\n\\nMyClass.increment_class_var()\\nprint(MyClass.class_var)\\nprint(MyClass.static_method())"]', '["1", "Static method called"]'),
('python', 126, 'intermediate', 1, '属性装饰器', '["属性","装饰器"]', '使用属性装饰器管理属性访问。', '属性装饰器如@property允许将方法作为属性访问。\n可以定义getter、setter和deleter。', '["class Person:\\n    def __init__(self, name):\\n        self._name = name\\n    @property\\n    def name(self):\\n        return self._name\\n    @name.setter\\n    def name(self, value):\\n        self._name = value\\n\\np = Person(\\"Alice\\")\\nprint(p.name)\\np.name = \\"Bob\\"\\nprint(p.name)"]', '["Alice", "Bob"]'),
('python', 127, 'intermediate', 1, '魔术方法__init__和__str__', '["魔术方法","__init__","__str__"]', '学习常用魔术方法如__init__用于初始化，__str__用于字符串表示。', '__init__方法在实例化时自动调用，用于初始化。\n__str__方法定义对象的字符串表示，用于print()。', '["class Book:\\n    def __init__(self, title, author):\\n        self.title = title\\n        self.author = author\\n    def __str__(self):\\n        return f\\"{self.title} by {self.author}\\"\\n\\nbook = Book(\\"Python Guide\\", \\"John Doe\\")\\nprint(book)"]', '["Python Guide by John Doe"]'),
('python', 128, 'intermediate', 1, '多重继承', '["多重继承"]', '探索多重继承的用法和注意事项。', '多重继承允许一个类继承多个父类。\n可能引发钻石问题，Python使用MRO解决。', '["class A:\\n    def method(self):\\n        return \\"A\\"\\nclass B:\\n    def method(self):\\n        return \\"B\\"\\nclass C(A, B):\\n    pass\\n\\nc = C()\\nprint(c.method())"]', '["A"]'),
('python', 129, 'intermediate', 1, '方法解析顺序', '["MRO","方法解析顺序"]', '理解Python的方法解析顺序如何工作。', 'MRO决定方法查找顺序，使用C3线性化算法。\n可以通过__mro__属性查看。', '["class A:\\n    def method(self):\\n        return \\"A\\"\\nclass B(A):\\n    pass\\nclass C(A):\\n    def method(self):\\n        return \\"C\\"\\nclass D(B, C):\\n    pass\\n\\nd = D()\\nprint(d.method())\\nprint(D.__mro__)"]', '["C", "(<class \\"__main__.D\\">, <class \\"__main__.B\\">, <class \\"__main__.C\\">, <class \\"__main__.A\\">, <class \\"object\\">)"]'),
('python', 130, 'intermediate', 1, '抽象基类', '["抽象基类","abc"]', '使用抽象基类定义接口。', '抽象基类定义抽象方法，子类必须实现。\n使用abc模块。', '["from abc import ABC, abstractmethod\\nclass Shape(ABC):\\n    @abstractmethod\\n    def area(self):\\n        pass\\nclass Circle(Shape):\\n    def __init__(self, radius):\\n        self.radius = radius\\n    def area(self):\\n        return 3.14 * self.radius ** 2\\n\\ncircle = Circle(5)\\nprint(circle.area())"]', '["78.5"]'),
('python', 131, 'intermediate', 1, '组合', '["组合","聚合"]', '通过组合构建复杂对象。', '组合通过将其他类实例作为属性来构建对象。\n与继承相比，更灵活。', '["class Engine:\\n    def start(self):\\n        return \\"Engine started\\"\\nclass Car:\\n    def __init__(self):\\n        self.engine = Engine()\\n    def start(self):\\n        return self.engine.start()\\n\\ncar = Car()\\nprint(car.start())"]', '["Engine started"]'),
('python', 132, 'intermediate', 1, '描述符', '["描述符"]', '理解描述符协议，控制属性访问。', '描述符是实现了__get__、__set__或__delete__方法的类。\n用于控制属性访问。', '["class Descriptor:\\n    def __get__(self, obj, objtype=None):\\n        return \\"Getting value\\"\\n    def __set__(self, obj, value):\\n        print(\\"Setting value to\\", value)\\nclass MyClass:\\n    attr = Descriptor()\\n\\nobj = MyClass()\\nprint(obj.attr)\\nobj.attr = 10"]', '["Getting value", "Setting value to 10"]'),
('python', 133, 'intermediate', 1, '元类基础', '["元类"]', '简介元类，类的类。', '元类是类的类，控制类的创建。\n使用type或自定义元类。', '["class Meta(type):\\n    def __new__(cls, name, bases, dct):\\n        dct[\\"custom_attr\\"] = \\"Added by meta\\"\\n        return super().__new__(cls, name, bases, dct)\\nclass MyClass(metaclass=Meta):\\n    pass\\n\\nprint(MyClass.custom_attr)"]', '["Added by meta"]'),
('python', 134, 'intermediate', 1, '混入类', '["混入类"]', '使用混入类为类添加功能。', '混入类是为其他类提供方法的类，通常不单独实例化。\n通过多重继承添加功能。', '["class Mixin:\\n    def mixin_method(self):\\n        return \\"Mixin method\\"\\nclass BaseClass:\\n    pass\\nclass MyClass(BaseClass, Mixin):\\n    pass\\n\\nobj = MyClass()\\nprint(obj.mixin_method())"]', '["Mixin method"]'),
('python', 135, 'intermediate', 1, '类变量与实例变量', '["类变量","实例变量"]', '区分类变量和实例变量的作用域。', '类变量在类定义中声明，所有实例共享。\n实例变量在__init__中定义，每个实例独立。', '["class MyClass:\\n    class_var = \\"class value\\"\\n    def __init__(self, instance_var):\\n        self.instance_var = instance_var\\n\\nobj1 = MyClass(\\"instance1\\")\\nobj2 = MyClass(\\"instance2\\")\\nprint(MyClass.class_var)\\nprint(obj1.instance_var)\\nprint(obj2.instance_var)\\nMyClass.class_var = \\"updated class\\"\\nprint(obj1.class_var)\\nprint(obj2.class_var)"]', '["class value", "instance1", "instance2", "updated class", "updated class"]');